module RefModule(
  input a,
  input b,
  input clk,
  output reg out
);reg a_ff, b_ff;
  wire xor1, xor2;

  always @(posedge clk) begin
    a_ff <= a;
    b_ff <= b;
  end

  wire __xor1_tmp = a_ff ^ b_ff;
  assign xor1 = __xor1_tmp;
  assign xor2 = a ^ b;

  always @(posedge clk) begin
    out <= xor1 ^ xor2;
  end

endmodule
